import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { uiRouteAuthoringRule } from "./ui-route-authoring.rule.js";

// Helper model declarations to include in test fixtures
// UiCommand, Stay, Pop, Push, Reload are exported from the library under the State namespace.
const UI_MODELS = ``;

describe("ui-route-authoring rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, uiRouteAuthoringRule, "@a10n/blueprint-typespec");
  });

  describe("valid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_01
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.no_mermaid_doc:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_projected_once_per_op:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.no_mermaid_doc:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.no_call_list:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_projected_once_per_op:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.no_call_list:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring
    it("T011_01: @uiRoute namespace with clean @doc — no diagnostic", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Ui })
          namespace Components.MyUi {
            ${UI_MODELS}
            @doc("Shows the list of tasks for the current user.")
            @uiRoute(#{ path: "/tasks" })
            namespace TaskListRoute {
              op on_mount(): UiCommand;
            }
          }
        `)
        .toBeValid();
    });

    it("T011_02: @uiRoute namespace without @doc — no diagnostic", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Ui })
          namespace Components.MyUi {
            ${UI_MODELS}
            @uiRoute(#{ path: "/tasks" })
            namespace TaskListRoute {
              op on_mount(): UiCommand;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_03
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.nav_return_type:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_projected_once_per_op:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.nav_return_type:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring
    it("T011_03: action op returning UiCommand — no nav-not-return-type diagnostic", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Ui })
          namespace Components.MyUi {
            ${UI_MODELS}
            @uiRoute(#{ path: "/tasks" })
            namespace TaskListRoute {
              op on_mount(): UiCommand;
            }
          }
        `)
        .toBeValid();
    });

    it("T011_04: non-uiRoute namespace — rule skips it", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {}
        `)
        .toBeValid();
    });

    // T011_07: inbound event action op covered only by test case — no event-handler decorator needed
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_07
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.path_discriminates_addressable:should
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.path_discriminates_addressable:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_projected_once_per_op:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.path_discriminates_addressable:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring
    it("T011_07: inbound event action op with no event-handler decorator — no diagnostic", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Ui })
          namespace Components.MyUi {
            ${UI_MODELS}
            @uiRoute(#{ path: "/tasks" })
            namespace TaskListRoute {
              op on_stream_delta(event: string): UiCommand;
            }
          }
        `)
        .toBeValid();
    });

    // T011_08: composition via nested namespace — no diagnostic
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_08
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.composition_via_nesting:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_projected_once_per_op:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.composition_via_nesting:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.route_not_callable:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_projected_once_per_op:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.route_not_callable:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring
    it("T011_08: composition via nested @uiRoute namespace — no diagnostic", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Ui })
          namespace Components.MyUi {
            ${UI_MODELS}
            @uiRoute(#{ path: "/tasks" })
            namespace TaskList {
              @uiRoute
              namespace FilterPanel {
                op on_apply(): UiCommand;
              }
              op on_mount(): UiCommand;
            }
          }
        `)
        .toBeValid();
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_05
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.no_mermaid_doc:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring
    it("T011_05: @uiRoute namespace @doc has Mermaid diagram — fires noMermaid", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Ui })
          namespace Components.MyUi {
            ${UI_MODELS}
            @doc("Flow:\\n\`\`\`mermaid\\ngraph TD;\\nA-->B;\\n\`\`\`")
            @uiRoute(#{ path: "/tasks" })
            namespace TaskListRoute {
              op on_mount(): UiCommand;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/ui-route-authoring",
          message: /TaskListRoute/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_06
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.no_call_list:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring
    it("T011_06: @uiRoute namespace @doc contains {@...} ref to a declared @calls target — fires noCallList", async () => {
      await ruleTester
        .expect(`
          namespace Components {
            @component(#{ type: ComponentType.Service })
            namespace TaskService {
              namespace Http {
                op list_tasks(): void;
              }
            }

            @component(#{ type: ComponentType.Ui })
            @dependsOn([Components.TaskService])
            namespace MyUi {
              @doc("On mount calls {\\@Components.TaskService.Http.list_tasks} to fetch data.")
              @uiRoute(#{ path: "/tasks" })
              namespace TaskListRoute {
                @calls([Components.TaskService.Http.list_tasks])
                op on_mount(): UiCommand;
              }
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/ui-route-authoring",
          message: /TaskListRoute/,
        });
    });

    // T011_pop_valid: Pop action op without naming parent route — no diagnostic
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.pop_is_anonymous:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_projected_once_per_op:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.pop_is_anonymous:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring
    it("Pop action op without naming parent route in @doc — no diagnostic", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Ui })
          namespace Components.MyUi {
            ${UI_MODELS}
            @uiRoute(#{ path: "/tasks" })
            namespace TaskListRoute {
              @doc("Closes this overlay.")
              op on_close(): Pop;
            }
          }
        `)
        .toBeValid();
    });

    // T016_09 (nav-not-return-type): action op returning void fires diagnostic
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.nav_return_type:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_ui_route_authoring
    it("T016_09: action op returning void — fires navNotReturnType", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Ui })
          namespace Components.MyUi {
            @uiRoute(#{ path: "/tasks" })
            namespace TaskListRoute {
              op on_cancel(): void;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/ui-route-authoring",
          message: /on_cancel/,
        });
    });
  });
});
